function mirror<T>(arg: T): T {
  return arg;
}

// We explicitly tell the function: "T is a string"
let output = mirror<string>("Hello");

// TS knows this evaluates to 'string' automatically!
let output1 = mirror("Hello");

// TS knows this evaluates to 'number' automatically!
let output2 = mirror(100);
